账户类型也对。那在 VPS 上加一行日志看看实际发出的 redirectUri：

```bash
docker exec iMail node -e "
const { ConfidentialClientApplication } = require('@azure/msal-node');
const cfg = require('./src/config');
const client = new ConfidentialClientApplication({
  auth: {
    clientId: cfg.outlook.client_id,
    clientSecret: cfg.outlook.client_secret,
    authority: 'https://login.microsoftonline.com/common',
  }
});
client.getAuthCodeUrl({
  scopes: ['https://graph.microsoft.com/Mail.Read', 'offline_access'],
  redirectUri: 'https://mail.idays.gq/api/emails/oauth/outlook/callback'
}).then(url => console.log(url)).catch(e => console.error(e.message));
"
```

把输出的 URL 发给我，看看里面的 `redirect_uri` 参数是什么。

容器里没有 sqlite3，用 node 执行：

```bash
docker exec iMail node -e "
const db = require('./src/db');
const oneMonthAgo = (Math.floor(Date.now()/1000) - 30*24*3600) * 1000;
const {changes} = db.prepare('UPDATE emails SET read = 1 WHERE read = 0 AND deleted = 0 AND (raw_date = 0 OR raw_date IS NULL OR raw_date < ?)').run(oneMonthAgo);
console.log('已标记:', changes);
"
```

BusyBox wget 不支持 cookie，用 node 直接调：

```bash
docker exec iMail node -e "
const http = require('http');
function req(opts, body, cb) {
  const r = http.request(opts, res => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => cb(res.headers, d));
  });
  if (body) r.write(body);
  r.end();
}
const loginBody = JSON.stringify({username:'admin',password:'890214'});
req({host:'localhost',port:3000,path:'/api/auth/login',method:'POST',headers:{'Content-Type':'application/json','Content-Length':loginBody.length}}, loginBody, (headers, body) => {
  const cookie = headers['set-cookie']?.[0]?.split(';')[0];
  console.log('login:', body);
  req({host:'localhost',port:3000,path:'/api/emails/sync/9b5734d5-4dbb-43fe-afdc-07286d11776d',method:'POST',headers:{Cookie:cookie}}, null, (h, b) => {
    console.log('sync:', b);
  });
});
"
```

添加后再触发同步，看同步结果：

```bash
docker exec iMail node -e "
const http = require('http');
function req(opts, body, cb) {
  const r = http.request(opts, res => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => cb(res.headers, d));
  });
  if (body) r.write(body);
  r.end();
}
const loginBody = JSON.stringify({username:'admin',password:'890214'});
req({host:'localhost',port:3000,path:'/api/auth/login',method:'POST',headers:{'Content-Type':'application/json','Content-Length':loginBody.length}}, loginBody, (headers, body) => {
  const cookie = headers['set-cookie']?.[0]?.split(';')[0];
  req({host:'localhost',port:3000,path:'/api/accounts',method:'GET',headers:{Cookie:cookie}}, null, (h, b) => {
    const accounts = JSON.parse(b).filter(a => a.type === 'outlook');
    console.log('Outlook账号:', accounts.map(a => a.email + ' ' + a.id));
  });
});
"
```

先看新添加的账号 id，再同步。
